import React, { useEffect, useRef } from 'react';
import './Hero.css';

/* Gear SVG com dentes triangulares para realismo */
function GearSVG({ teeth = 12, outerR = 90, innerR = 70, toothH = 8, holeR = 22, color = 'rgba(59,130,246,0.18)', strokeW = 1.5 }) {
  const cx = 100, cy = 100;
  const points = [];
  const total = teeth * 3; // 3 pontos por dente para forma triangular

  for (let i = 0; i < total; i++) {
    const angle = (i / total) * Math.PI * 2 - Math.PI / 2;
    const toothIndex = i % 3;
    let r;
    if (toothIndex === 0) r = innerR; // base esquerda
    else if (toothIndex === 1) r = outerR + toothH; // ponta
    else r = innerR; // base direita
    points.push(`${cx + r * Math.cos(angle)},${cy + r * Math.sin(angle)}`);
  }

  const d = `M ${points.join(' L ')} Z`;

  return (
    <svg viewBox="0 0 200 200" fill="none" xmlns="http://www.w3.org/2000/svg" style={{ width: '100%', height: '100%' }}>
      <path d={d} fill={color} stroke={color.replace('0.18', '0.35')} strokeWidth={strokeW} strokeLinejoin="round" />
      <circle cx={cx} cy={cy} r={holeR} fill="transparent" stroke={color.replace('0.18', '0.35')} strokeWidth={strokeW} />
      <circle cx={cx} cy={cy} r={holeR * 0.55} fill={color} />
    </svg>
  );
}

export default function Hero() {
  const gear1Ref = useRef(null);
  const gear2Ref = useRef(null);
  const gear3Ref = useRef(null);

  useEffect(() => {
    let angle = 0;
    let raf;
    const tick = () => {
      angle += 0.08;
      if (gear1Ref.current) gear1Ref.current.style.transform = `rotate(${angle}deg)`;
      if (gear2Ref.current) gear2Ref.current.style.transform = `rotate(${-angle * 1.4}deg)`;
      if (gear3Ref.current) gear3Ref.current.style.transform = `rotate(${angle * 0.6}deg)`;
      raf = requestAnimationFrame(tick);
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, []);

  const scrollTo = (id) => document.querySelector(id)?.scrollIntoView({ behavior: 'smooth' });

  return (
    <section id="hero" className="hero">
      <div className="noise-overlay" />
      <div className="grid-lines" />

      {/* Decorative gears — right side */}
      <div className="hero__gear-bg" aria-hidden="true">
        <div ref={gear1Ref} className="hero__gear hero__gear--1">
          <GearSVG teeth={14} outerR={92} innerR={74} toothH={8} holeR={24} color="rgba(59,130,246,0.13)" />
        </div>
        <div ref={gear2Ref} className="hero__gear hero__gear--2">
          <GearSVG teeth={10} outerR={88} innerR={70} toothH={8} holeR={20} color="rgba(34,85,204,0.18)" />
        </div>
        <div ref={gear3Ref} className="hero__gear hero__gear--3">
          <GearSVG teeth={8} outerR={85} innerR={68} toothH={8} holeR={18} color="rgba(59,130,246,0.10)" />
        </div>
      </div>

      {/* Accent lines */}
      <div className="hero__accent-lines" aria-hidden="true">
        <div className="hero__line hero__line--1" />
        <div className="hero__line hero__line--2" />
        <div className="hero__line hero__line--3" />
      </div>

      <div className="container hero__content">
        <br/><br/>

        <h1 className="hero__title">
          ENGENHARIA<br />
          <span>INDUSTRIAL</span><br />
          DE ALTO NÍVEL
        </h1>

        <p className="hero__sub">
          A AME entrega soluções completas em automação, manutenção e engenharia industrial — 
          unindo tecnologia de ponta à experiência comprovada para maximizar a produtividade da sua planta.
        </p>

        <div className="hero__actions">
          <button className="btn-primary" onClick={() => scrollTo('#servicos')}>
            <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
              <path d="M13 2L3 14h9l-1 8 10-12h-9l1-8z" />
            </svg>
            Nossos Serviços
          </button>
          <button className="btn-outline" onClick={() => scrollTo('#contato')}>
            Fale Conosco
          </button>
        </div>

        {/* Stats */}
        <div className="hero__stats">
          {[
            { value: '15+',  label: 'Anos de Experiência' },
            { value: '200+', label: 'Projetos Entregues' },
            { value: '50+',  label: 'Clientes Ativos' },
            { value: '99%',  label: 'Satisfação' },
          ].map(({ value, label }) => (
            <div key={label} className="hero__stat">
              <span className="hero__stat-value">{value}</span>
              <span className="hero__stat-label">{label}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Scroll indicator */}
      <button className="hero__scroll" onClick={() => scrollTo('#sobre')}>
        <span>Saiba Mais</span>
        <div className="hero__scroll-icon">
          <svg width="16" height="16" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
            <path d="M12 5v14M5 12l7 7 7-7" />
          </svg>
        </div>
      </button>
    </section>
  );
}
